import dspy
import vex

class LegalCoT(dspy.Module):
    def __init__(self):
        super().__init__()
        self.analyze = dspy.ChainOfThought('facts -> legal_reasoning -> conclusion')

    def forward(self, facts):
        reasoning = self.analyze(facts=facts)

        @vex.verify({
            'logic_valid': {'type': 'boolean'},
            'no_hallucinations': {'type': 'boolean'}
        })
        def verify_reasoning(reasoning):
            return reasoning

        verified = verify_reasoning(reasoning)
        return verified

import dspy
import vex

class PrivilegedDocClassifier(dspy.Module):
    def __init__(self):
        super().__init__()
        self.classify = dspy.Predict('document -> is_privileged,confidence,reasons')

    def forward(self, document):
        raw_pred = self.classify(document=document)

        result = vex.verify(raw_pred, {
            'is_privileged': {'type': 'boolean'},
            'confidence': {'type': 'number', 'minimum': 0, 'maximum': 1},
            'pii_detected': {'type': 'boolean'},
            'audit_log': {'type': 'boolean'}
        })

        if not result.compliant:
            raise ValueError('Document classification failed compliance check')
        return result
